import React, { useState, useEffect, useRef } from 'react';
import { useMessaging } from '../../context/MessagingContext';
import { Send, PlusIcon } from '../../../../components/icons';
import MentionSuggestionsList from './MentionSuggestionsList';

const MessageComposer: React.FC = () => {
    const [text, setText] = useState('');
    const { handleSend, allUsers } = useMessaging();
    const [mentionQuery, setMentionQuery] = useState<string | null>(null);
    const composerRef = useRef<HTMLDivElement>(null);
    const inputRef = useRef<HTMLInputElement>(null);
    const fileInputRef = useRef<HTMLInputElement>(null);

    useEffect(() => {
        const atIndex = text.lastIndexOf('@');
        const currentSelection = inputRef.current?.selectionStart || 0;
        const spaceAfterAtIndex = text.indexOf(' ', atIndex);

        if (atIndex > -1 && (spaceAfterAtIndex === -1 || spaceAfterAtIndex > currentSelection)) {
            const query = text.substring(atIndex + 1, currentSelection);
            setMentionQuery(query);
        } else {
            setMentionQuery(null);
        }
    }, [text]);

    const handleSelectMention = (user: {id: string, name: string}) => {
        const atIndex = text.lastIndexOf('@');
        const textBefore = text.substring(0, atIndex);
        const mentionText = `@[${user.name}](${user.id}) `;

        setText(textBefore + mentionText);
        setMentionQuery(null);
        inputRef.current?.focus();
    };

    const handleAttachmentClick = () => {
        fileInputRef.current?.click();
    };

    const handleFileChange = (e: React.ChangeEvent<HTMLInputElement>) => {
        const file = e.target.files?.[0];
        if (file) {
            // In a real app, upload file here. For now, simulate adding a tag to text.
            setText(prev => `${prev} [Attachment: ${file.name}] `);
            // Clear input so same file can be picked again
            e.target.value = '';
        }
    };

    const handleSubmit = (e: React.FormEvent) => {
        e.preventDefault();
        if (text.trim()) {
            handleSend(text.trim());
            setText('');
        }
    };

    return (
        <div ref={composerRef} className="relative">
            {mentionQuery !== null && (
                <MentionSuggestionsList
                    query={mentionQuery}
                    users={allUsers}
                    onSelect={handleSelectMention}
                    onClose={() => setMentionQuery(null)}
                />
            )}
            <form onSubmit={handleSubmit} className="flex items-center gap-2">
                <input 
                    type="file" 
                    ref={fileInputRef} 
                    className="hidden" 
                    onChange={handleFileChange}
                    accept=".pdf,.jpg,.jpeg,.png,.doc,.docx"
                />
                <button
                    type="button"
                    onClick={handleAttachmentClick}
                    className="btn-neu p-3 text-slate-500 hover:text-sky-600 transition-colors"
                    title="Attach file"
                >
                    <PlusIcon className="w-5 h-5" />
                </button>
                <input
                    ref={inputRef}
                    type="text"
                    value={text}
                    onChange={(e) => setText(e.target.value)}
                    placeholder="Type a message... use '@' to mention"
                    className="input-neu w-full"
                    autoComplete="off"
                />
                <button
                    type="submit"
                    className="btn-neu p-3 text-sky-600 disabled:text-slate-400"
                    disabled={!text.trim()}
                    aria-label="Send message"
                >
                    <Send className="w-5 h-5" />
                </button>
            </form>
        </div>
    );
};

export default MessageComposer;

import React, { useEffect } from 'react';
import { useLocation, useNavigate } from 'react-router-dom';
