  const fetchAppointments = useCallback(async () => {
    setAppointmentsLoading(true);
    setAppointmentsError(null);

    try {
      const appointments = await appointmentService.fetchAppointments();
      setAllAppointments(appointments);
    } catch (error) {
      setAppointmentsError('Failed to load appointments');
      console.error('Error fetching appointments:', error);
    } finally {
      setAppointmentsLoading(false);
    }
  }, []);

  useEffect(() => {
    fetchRecords();
    fetchAppointments();
  }, [fetchRecords, fetchAppointments]);

  const upcomingAppointments = useMemo(() => {
    if (!patientId) return [];
    const now = new Date();
    return allAppointments
      .filter(a => 
        a.patientId === patientId && 
        (new Date(a.startTime) > now || a.status === 'in_progress') && 
        (a.status === 'confirmed' || a.status === 'scheduled' || a.status === 'checked_in' || a.status === 'in_progress')
      )
      .sort((a, b) => new Date(a.startTime).getTime() - new Date(b.startTime).getTime());
  }, [allAppointments, patientId]);

  return {
    records,
    recordsLoading,
    recordsError,
    appointmentsLoading,
    appointmentsError,
    upcomingAppointments,
    refetchRecords: fetchRecords,
    refetchAppointments: fetchAppointments,
  };
};

