                    onClose={() => setAppointmentToEdit(null)}
                    onSave={handleUpdateAppointment}
                    appointment={appointmentToEdit}
                />

                <ConfirmationModal
                    isOpen={!!appointmentToCancel}
                    onClose={() => setAppointmentToCancel(null)}
                    onConfirm={handleConfirmCancel}
                    title="Confirm Appointment Cancellation"
                >
                    <p className="text-lg text-slate-800">
                    Are you sure you want to cancel the session for{' '}
                    <span className="font-black text-red-600">{patientForCancellation?.name}</span>?
                    </p>
                    <p className="mt-3 text-slate-500 font-medium">
                    This action is permanent. The automated notification system will alert the patient immediately.
                    </p>
                </ConfirmationModal>
                </>
            )}
        </>,
        document.body
      )}
    </div>
  );
};

