import React, { useState, useEffect, useMemo } from 'react';
import { motion, AnimatePresence } from 'framer-motion'; // Added for Surface physics
import { createPortal } from 'react-dom';
import * as ReactRouterDOM from 'react-router-dom';
import {
  CalendarIcon, FileText, BeakerIcon, ClockIcon, 
  UserPlusIcon, User, WrenchIcon, XIcon, SearchIcon, ArrowRightIcon
} from '../../../../components/icons';
import { appointmentService } from '../../../AppointmentsMFE/services/appointmentService';
import { useAuth } from '../../../PatientMFE/hooks/useAuth';
import { usePatients } from '../../../PatientMFE/context/PatientContext';
import SmartAssistant from './SmartAssistant';
import TeamSignal from './TeamSignal';
import TodaysAppointmentsList from './TodaysAppointmentsList';

// New: Wrapper for "Surface" objects to handle rotation and dragging
const SurfaceObject: React.FC<{ children: React.ReactNode; defaultDegree?: number }> = ({ children, defaultDegree = 0 }) => (
  <motion.div
    drag
    dragMomentum={true}
    initial={{ rotate: defaultDegree, scale: 0.9, opacity: 0 }}
    animate={{ scale: 1, opacity: 1 }}
    whileDrag={{ scale: 1.02, zIndex: 50 }}
    style={{ touchAction: 'none' }}
    className="absolute cursor-grab active:cursor-grabbing"
  >
    {children}
  </motion.div>
);

const ClinicianDashboard: React.FC = () => {
  const { user: currentUser } = useAuth(); // [cite: 8]
  const { getPatientById } = usePatients(); // [cite: 9]
  const navigate = ReactRouterDOM.useNavigate();

  const [appointments, setAppointments] = useState([]);
  const [selectedAppointment, setSelectedAppointment] = useState(null);
  const [isToolsOpen, setIsToolsOpen] = useState(false);

  useEffect(() => {
    const fetch = async () => {
      const data = await appointmentService.fetchAppointments();
      setAppointments(data);
    };
    fetch();
  }, []);

  const activePatient = useMemo(() => {
    return appointments.find(a => a.status === 'in_progress') || appointments[0];
  }, [appointments]);

  const activePatientDetails = activePatient ? getPatientById(activePatient.patientId) : null; // [cite: 21]

  return (
    // Change: The main container is now a relative "Table" instead of a flex-row
    <div className="relative w-full h-screen bg-[#0f172a] overflow-hidden p-6 perspective-1000">

      {/* Background Ambient Glows to mimic the video aesthetic */}
      <div className="absolute top-[-10%] left-[-10%] w-96 h-96 bg-sky-500/10 rounded-full blur-[120px]" />

      {/* OBJECT 1: The Interactive Queue (Moved from ZONE A) */}
      <SurfaceObject defaultDegree={-1}>
        <div className="glass-panel-heavy w-[550px] shadow-2xl border border-white/20 rounded-[40px] overflow-hidden">
          <div className="p-8 bg-white/5 border-b border-white/10">
            <h2 className="text-2xl font-black text-white flex items-center gap-4">
              <User className="w-8 h-8 text-sky-400" />
              Patient Workspace [cite: 45]
            </h2>
          </div>

          <div className="p-8 space-y-6">
            {activePatientDetails && (
              <div className="bg-gradient-to-br from-indigo-600 to-blue-700 p-8 rounded-[32px] text-white shadow-xl">
                <div className="flex items-center gap-6">
                  <img src={activePatientDetails.avatar} className="w-20 h-20 rounded-full border-4 border-white/30" alt="" />
                  <div className="flex-1">
                    <span className="text-[10px] font-black uppercase tracking-widest text-sky-200">Active Queue [cite: 50]</span>
                    <h3 className="text-3xl font-black">{activePatientDetails.name}</h3>
                  </div>
                  <button onClick={() => setSelectedAppointment(activePatient)} className="bg-white text-indigo-700 p-4 rounded-2xl">
                    <ArrowRightIcon />
                  </button>
                </div>
              </div>
            )}
            <TodaysAppointmentsList appointments={appointments.slice(1, 4)} variant="upcoming" />
          </div>
        </div>
      </SurfaceObject>

      {/* OBJECT 2: Intelligence Stream (Moved from ZONE B) */}
      <SurfaceObject defaultDegree={2}>
        <div className="glass-panel-heavy w-[400px] left-[600px] top-[100px] border border-white/10 rounded-[40px] p-8">
          <h2 className="text-xl font-bold text-white mb-6">Practice Intelligence [cite: 66]</h2>
          <SmartAssistant suggestions={[]} />
          <div className="mt-8">
            <TeamSignal injectedActivities={[]} />
          </div>
        </div>
      </SurfaceObject>

      {/* RADIAL MENU: Replacement for the ToolsList and Sidebar [cite: 35-38, 74] */}
      <div className="absolute bottom-12 left-1/2 -translate-x-1/2 flex items-center justify-center">
        <motion.button 
          onClick={() => setIsToolsOpen(!isToolsOpen)}
          className="w-24 h-24 bg-white rounded-full shadow-[0_0_50px_rgba(0,150,255,0.3)] z-[100] flex items-center justify-center"
        >
          <WrenchIcon className="w-10 h-10 text-slate-900" />
        </motion.button>

        <AnimatePresence>
          {isToolsOpen && (
            <motion.div className="absolute z-50">
              {/* Radial placement of your QuickAction items  */}
              {[
                { icon: UserPlusIcon, label: "New", pos: "top-[-140px] left-[-140px]" },
                { icon: CalendarIcon, label: "Schedule", pos: "top-[-180px] left-0" },
                { icon: BeakerIcon, label: "Labs", pos: "top-[-140px] left-[140px]" }
              ].map((tool, i) => (
                <motion.button
                  key={i}
                  initial={{ scale: 0, opacity: 0 }}
                  animate={{ scale: 1, opacity: 1 }}
                  exit={{ scale: 0 }}
                  className={`absolute ${tool.pos} w-20 h-20 glass-panel-heavy rounded-full flex flex-col items-center justify-center text-[10px] text-white font-bold`}
                >
                  <tool.icon className="w-6 h-6 mb-1" />
                  {tool.label}
                </motion.button>
              ))}
            </motion.div>
          )}
        </AnimatePresence>
      </div>
    </div>
  );
};

export default ClinicianDashboard;

