    className={`absolute ${className}`}
  >
    {children}
  </motion.div>
);

const ClinicianDashboard: React.FC = () => {
  const { user: currentUser } = useAuth();
  const { getPatientById } = usePatients();
  const navigate = ReactRouterDOM.useNavigate();

  const [appointments, setAppointments] = useState<Appointment[]>([]);
  const [isLoadingAppointments, setIsLoadingAppointments] = useState(true);
  const [radialOpen, setRadialOpen] = useState(false);

  const [selectedAppointment, setSelectedAppointment] = useState<Appointment | null>(null);
  const [appointmentToEdit, setAppointmentToEdit] = useState<Appointment | null>(null);
  const [appointmentToCancel, setAppointmentToCancel] = useState<Appointment | null>(null);
  const [teamEvents, setTeamEvents] = useState<any[]>([]);

  const fetchAppointments = async () => {
    setIsLoadingAppointments(true);
    try {
      const data = await appointmentService.fetchAppointments();
      setAppointments(data);
    } catch (error) {
      console.error('Failed to fetch appointments:', error);
    } finally {
      setIsLoadingAppointments(false);
    }
  };

  useEffect(() => {
    fetchAppointments();
  }, []);

  const allTodaysAppointments = useMemo(() => {
    const now = new Date();
    const startOfDay = new Date(now.getFullYear(), now.getMonth(), now.getDate());
    const endOfDay = new Date(now.getFullYear(), now.getMonth(), now.getDate() + 1);

    return appointments.filter(appt => {
      const apptDate = new Date(appt.startTime);
      return apptDate >= startOfDay && apptDate < endOfDay;
    });
  }, [appointments]);

  const upcomingTodaysAppointments = useMemo(() => {
    const now = new Date();
    return allTodaysAppointments
      .filter(appt => new Date(appt.startTime) >= now && appt.status !== 'cancelled' && appt.status !== 'completed')
      .sort((a, b) => new Date(a.startTime).getTime() - new Date(b.startTime).getTime());
  }, [allTodaysAppointments]);

  const completedTodaysAppointments = useMemo(() => {
    return allTodaysAppointments
      .filter(appt => appt.status === 'completed')
      .sort((a, b) => b.startTime.localeCompare(a.startTime));
  }, [allTodaysAppointments]);

  const activePatient = upcomingTodaysAppointments[0];
  const activePatientDetails = activePatient ? getPatientById(activePatient.patientId) : null;

  const handleUpdateAppointment = async (appointmentData: Appointment) => {
      if (!currentUser) return;
      await appointmentService.updateAppointment(appointmentData, currentUser.id);
      await fetchAppointments();
      setAppointmentToEdit(null);
  };

  const handleConfirmCancel = async () => {
      if (!appointmentToCancel || !currentUser) return;
      await appointmentService.updateAppointmentStatus(
        appointmentToCancel.id, 
        'cancelled', 
        currentUser.id, 
        "Cancelled by administrator."
      );
      await fetchAppointments();
      setSelectedAppointment(null);
      setAppointmentToCancel(null);
  };

  const handleOpenEditModal = (appointment: Appointment) => {
    setSelectedAppointment(null);
    setAppointmentToEdit(appointment);
  };

  const handleStartVisit = async (appointment: Appointment) => {
      if (!currentUser) return;
      await appointmentService.updateAppointmentStatus(appointment.id, 'in_progress', currentUser.id);
      await fetchAppointments();
      setSelectedAppointment(null); 
      navigate(`/patients/${appointment.patientId}?view=Medical+Records`);
  };

  const patientForCancellation = useMemo(() => {
    if (!appointmentToCancel) return null;
    return getPatientById(appointmentToCancel.patientId);
  }, [appointmentToCancel, getPatientById]);

  return (
    <div className="fixed inset-0 bg-[#0a0f18] overflow-hidden selection:bg-sky-500/30">
      {/* Background Ambience */}
      <div className="absolute top-[-10%] left-[-10%] w-[50%] h-[50%] bg-sky-500/10 blur-[150px] rounded-full pointer-events-none" />
      <div className="absolute bottom-[-10%] right-[-10%] w-[40%] h-[40%] bg-indigo-500/10 blur-[120px] rounded-full pointer-events-none" />

      {/* HUD: Global Stats */}
      <div className="absolute top-10 right-10 z-50">
        <SmartBadge 
            completed={completedTodaysAppointments.length} 
            total={allTodaysAppointments.length} 
            pendingNotes={3} 
        />
      </div>

      <div className="absolute top-10 left-10 z-50">
          <h1 className="text-4xl font-black text-white tracking-tighter">
              Care<span className="text-sky-400">Plus</span>
          </h1>
          <p className="text-white/40 text-[10px] font-bold uppercase tracking-[0.3em] mt-1">Terminal Node • {currentUser?.name}</p>
      </div>

      {/* Surface Object 1: Patient Queue */}
      <SurfaceObject defaultPos={{ x: 60, y: 140 }} rotate={-0.5}>
        <div className="glass-panel-heavy w-[580px] rounded-[40px] overflow-hidden border border-white/20">
          <div className="p-8 cursor-grab active:cursor-grabbing bg-white/5 border-b border-white/10 flex items-center justify-between">
            <h2 className="text-2xl font-black text-white flex items-center gap-4">
              <User className="w-8 h-8 text-sky-400" />
              Patient Workspace
            </h2>
            <div className="flex gap-1.5">
                <div className="w-2.5 h-2.5 rounded-full bg-white/20" />
                <div className="w-2.5 h-2.5 rounded-full bg-white/20" />
            </div>
          </div>

          <div className="p-8 space-y-8 max-h-[700px] overflow-y-auto custom-scrollbar">
            {activePatientDetails ? (
              <div className="bg-gradient-to-br from-blue-600/90 to-indigo-700/90 rounded-[36px] p-8 border border-white/20 shadow-2xl relative overflow-hidden group">
                  <div className="relative z-10 flex items-center gap-6">
                    <img src={activePatientDetails.avatar} className="w-20 h-20 rounded-full border-4 border-white/30" alt="" />
                    <div className="flex-1">
                      <span className="text-[10px] font-black text-sky-200 uppercase tracking-widest bg-white/10 px-2 py-0.5 rounded">In Queue</span>
                      <h3 className="text-3xl font-black text-white mt-1">{activePatientDetails.name}</h3>
                      <p className="text-blue-100/70 text-sm mt-1 italic line-clamp-1">"{activePatient.reason}"</p>
                    </div>
                    <button 
                      onClick={() => setSelectedAppointment(activePatient)}
                      className="w-14 h-14 bg-white text-indigo-700 rounded-2xl flex items-center justify-center hover:scale-110 transition-transform shadow-lg"
                    >
                      <ArrowRightIcon className="w-6 h-6" />
                    </button>
                  </div>
                  <div className="absolute -right-16 -bottom-16 w-48 h-48 bg-white/5 rounded-full blur-3xl" />
              </div>
            ) : (
                <div className="p-12 text-center text-white/30 border-2 border-dashed border-white/10 rounded-[36px]">
                    <SearchIcon className="w-12 h-12 mx-auto mb-4 opacity-50" />
                    <p className="font-bold uppercase tracking-widest text-xs">Queue Terminal Offline</p>
                </div>
            )}

            <div className="space-y-4">
                <h3 className="text-[10px] font-black text-white/40 uppercase tracking-[0.3em] px-2">Next Scheduled</h3>
                <div className="rounded-[24px] overflow-hidden bg-white/5 border border-white/5">
                    <TodaysAppointmentsList 
                        appointments={upcomingTodaysAppointments.slice(1, 4)} 
                        onSelectAppointment={setSelectedAppointment}
                        isLoading={isLoadingAppointments}
                        variant="upcoming"
                    />
                </div>
            </div>
          </div>
        </div>
      </SurfaceObject>

      {/* Surface Object 2: Intelligence & Signals */}
      <SurfaceObject defaultPos={{ x: 680, y: 160 }} rotate={0.8}>
        <div className="glass-panel-heavy w-[440px] rounded-[40px] p-8 border border-white/20">
          <div className="cursor-grab active:cursor-grabbing mb-8">
            <h2 className="text-xl font-black text-white uppercase tracking-widest flex items-center gap-3">
              <Sparkles className="w-5 h-5 text-sky-400" />
              Clinical Signals
            </h2>
          </div>

          <div className="space-y-6 max-h-[600px] overflow-y-auto custom-scrollbar">
            <div className="grid grid-cols-2 gap-4">
                <div className="bg-white/5 border border-white/10 p-5 rounded-3xl group hover:bg-white/10 transition-colors">
                    <ClockIcon className="w-6 h-6 text-orange-400 mb-2" />
                    <p className="text-2xl font-black text-white">12m</p>
                    <p className="text-[9px] font-bold text-white/40 uppercase tracking-widest">Wait Time</p>
                </div>
                <div className="bg-white/5 border border-white/10 p-5 rounded-3xl group hover:bg-white/10 transition-colors">
                    <BeakerIcon className="w-6 h-6 text-emerald-400 mb-2" />
                    <p className="text-2xl font-black text-white">5</p>
                    <p className="text-[9px] font-bold text-white/40 uppercase tracking-widest">Pending Labs</p>
                </div>
            </div>

            <SmartAssistant suggestions={[{ id: 'act-1', text: 'Review abnormal cortisol result: Carter, B.', type: 'urgent', actionLabel: 'Open' }]} />
            <TeamSignal />
          </div>
        </div>
      </SurfaceObject>

      {/* Radial Menu Trigger */}
      <div className="absolute bottom-16 left-1/2 -translate-x-1/2 z-[200]">
          <button 
              onClick={() => setRadialOpen(!radialOpen)}
              className={`w-24 h-24 rounded-full flex items-center justify-center shadow-[0_0_80px_rgba(0,180,255,0.4)] transition-all duration-500 transform ${radialOpen ? 'bg-slate-800 rotate-45' : 'bg-white hover:scale-110 active:scale-95'}`}
          >
              <WrenchIcon className={`w-10 h-10 transition-colors duration-500 ${radialOpen ? 'text-white' : 'text-slate-900'}`} />
          </button>

          <AnimatePresence>
            {radialOpen && (
              <div className="absolute bottom-1/2 left-1/2 -translate-x-1/2 -translate-y-1/2 pointer-events-none">
                <motion.div
                    initial={{ scale: 0, opacity: 0 }}
                    animate={{ scale: 1, opacity: 1 }}
                    exit={{ scale: 0, opacity: 0 }}
                    className="relative w-[360px] h-[360px] flex items-center justify-center pointer-events-auto"
                >
                    {/* Satellite Actions */}
                    {[
                        { icon: UserPlusIcon, label: "New", color: "bg-blue-600", path: "/patients/new", angle: -135 },
                        { icon: CalendarIcon, label: "Schedule", color: "bg-purple-600", path: "/appointments", angle: -90 },
                        { icon: BeakerIcon, label: "Labs", color: "bg-emerald-600", path: "/test-ordering", angle: -45 },
                    ].map((tool, i) => (
                        <motion.button
                            key={i}
                            whileHover={{ scale: 1.1 }}
                            whileTap={{ scale: 0.95 }}
                            onClick={() => { setRadialOpen(false); navigate(tool.path); }}
                            className={`absolute w-20 h-20 rounded-full flex flex-col items-center justify-center shadow-xl border border-white/20 glass-panel-heavy`}
                            style={{
                                transform: `translate(calc(cos(${tool.angle}deg) * 140px), calc(sin(${tool.angle}deg) * 140px))`,
                            }}
                        >
                            <div className={`w-10 h-10 ${tool.color} rounded-xl flex items-center justify-center mb-1 shadow-inner`}>
                                <tool.icon className="w-5 h-5 text-white" />
                            </div>
                            <span className="text-[10px] font-black text-white uppercase tracking-widest">{tool.label}</span>
                        </motion.button>
                    ))}
                </motion.div>
              </div>
            )}
          </AnimatePresence>
      </div>

      {/* Global Portals */}
      {createPortal(
        <>
            {currentUser && (
                <>
                <AppointmentDetailModal 
                    isOpen={!!selectedAppointment}
                    onClose={() => setSelectedAppointment(null)}
                    appointment={selectedAppointment}
                    currentUser={currentUser}
                    onRequestAction={() => {}} 
                    onAdminCancel={setAppointmentToCancel}
                    onAdminEdit={handleOpenEditModal}
                    onStatusUpdate={fetchAppointments}
                    onStartVisit={handleStartVisit}
                />
                <EditAppointmentModal 
                    isOpen={!!appointmentToEdit}
                    onClose={() => setAppointmentToEdit(null)}
                    onSave={handleUpdateAppointment}
                    appointment={appointmentToEdit}
                />
                <ConfirmationModal
                    isOpen={!!appointmentToCancel}
                    onClose={() => setAppointmentToCancel(null)}
                    onConfirm={handleConfirmCancel}
                    title="Cancel Session"
                >
                    <p className="text-slate-600">Permanently remove this session for <span className="font-bold text-slate-900">{patientForCancellation?.name}</span> from the board?</p>
                </ConfirmationModal>
                </>
            )}
        </>,
        document.body
      )}
    </div>
  );
};

export default ClinicianDashboard;
